function verifierEtatCloud() { var base = MOUACHIR_API || ''; fetch(base + "/api/cloud-status").then(function(r) { return r.json(); }).then(function(data) { if (data.pret && data.comptes && Object.keys(data.comptes).length) { if (data.connectes) Object.assign(_cloudConnectes, data.connectes); var select = $("#select-cloud-compte"); select.innerHTML = ""; Object.entries(data.comptes).forEach(function(pair) { var provider = pair[0], noms = pair[1]; noms.forEach(function(nom) { var opt = document.createElement("option"); opt.value = provider + "::" + nom; var key = provider + "::" + nom; var connecte = _cloudConnectes[key]; var icone = ""; if (connecte === true) icone = "🔑 "; else if (connecte === false) icone = "🔒 "; opt.textContent = icone + (NOMS_PROVIDERS[provider] || provider) + " — " + nom; select.appendChild(opt); }); }); $("#cloud-row").style.display = "flex"; onCloudCompteChange(); } }).catch(function() {}); }
function onCloudCompteChange() { var select = $("#select-cloud-compte"); var key = select.value; var connecte = _cloudConnectes[key]; var btnCloud = $("#btn-telecharger-cloud"); var btnCloudPlus = $("#btn-telecharger-plus-cloud"); var btnConnect = $("#btn-connecter-cloud"); if (connecte === false) { btnCloud.style.display = "none"; btnCloudPlus.style.display = "none"; btnConnect.style.display = "inline-flex"; } else { btnCloud.style.display = "inline-flex"; btnCloudPlus.style.display = "inline-flex"; btnConnect.style.display = "none"; } }
document.addEventListener("click", function(e) { if (e.target.id === "btn-connecter-cloud") { var key = $("#select-cloud-compte").value; var parts = key.split("::"); var provider = parts[0], compte = parts[1]; if (provider === "gdrive") { logLine($("#download-log"), "🔑 Ouverture du navigateur pour l'authentification Google..."); var base = MOUACHIR_API || ''; fetch(base + "/api/cloud/google/auth?compte=" + encodeURIComponent(compte)).then(function(r) { return r.json(); }).then(function(d) { if (d.url) window.open(d.url, "cloud-oauth", "width=500,height=600,left=200,top=100"); var poll = setInterval(function() { fetch(base + "/api/cloud/google/auth-status/" + encodeURIComponent(compte)).then(function(r) { return r.json(); }).then(function(sd) { if (sd.status === "connected") { clearInterval(poll); logLine($("#download-log"), "🔑 Compte " + compte + " connecté !"); verifierEtatCloud(); } else if (sd.status === "error") { clearInterval(poll); logLine($("#download-log"), "❌ Échec : " + (sd.error || "erreur inconnue")); } }); }, 1500); }).catch(function(e) { alert("Erreur : " + e.message); }); } else { alert("L'authentification automatique n'est pas encore supportée pour ce provider."); } } });
document.addEventListener("DOMContentLoaded", function() { initSiteCards(); verifierEtatCloud(); setInterval(verifierEtatCloud, 30000); $("#select-cycle").addEventListener("change", onCycleChange); $("#select-niveau").addEventListener("change", onNiveauChange); $("#btn-decouvrir").addEventListener("click", lancerDecouverte); $("#btn-annuler-decouverte").addEventListener("click", annulerDecouverteCourante); $("#btn-telecharger").addEventListener("click", function() { lancerTelechargement("normal"); }); $("#btn-telecharger-zip").addEventListener("click", function() { lancerTelechargement("zip"); }); $("#btn-telecharger-cloud").addEventListener("click", envoyerVersCloud); $("#btn-telecharger-plus-cloud").addEventListener("click", lancerTelechargementCloud); $("#select-cloud-compte").addEventListener("change", onCloudCompteChange); $("#btn-annuler-telechargement").addEventListener("click", annulerTelechargementCourant); $("#btn-reinitialiser").addEventListener("click", reinitialiserDashboard); });
